import React, { useState } from 'react';
import './CompetitionsPage.css';

const competitionsData = {
  '2022': {
    panitia: '/esc-24-25.jpg',
    events: [
      {
        id: 'drone',
        title: 'Drone',
        img: '/workshop-drone.jpg',
        desc: 'Kompetisi drone racing dan misi otomatis yang menguji kemampuan navigasi dan kontrol UAV secara presisi.',
      },
      {
        id: 'wf',
        title: 'WF',
        img: '/workshop-drone.jpg',
        desc: 'Workshop Festival — ajang unjuk kreativitas dan inovasi teknologi.',
      },
      {
        id: 'rcv',
        title: 'Robot Computer Vision',
        img: '/workshop-drone.jpg',
        desc: 'Robot berbasis computer vision yang mampu mendeteksi objek real-time.',
      },
    ],
  },
  '2025': {
    panitia: '/esc-22-23.jpg',
    events: [
      {
        id: 'drone',
        title: 'Drone',
        img: '/workshop-drone.jpg',
        desc: 'Kompetisi drone racing.',
      },
      {
        id: 'wf',
        title: 'WF',
        img: '/workshop-drone.jpg',
        desc: 'Workshop Festival.',
      },
      {
        id: 'gripper',
        title: 'Robot Gripper',
        img: '/workshop-drone.jpg',
        desc: 'Robot gripper otomatis.',
      },
    ],
  },
  '2026': {
    panitia: '/esc-24-25.jpg',
    events: [
      {
        id: 'drone',
        title: 'Drone',
        img: '/workshop-drone.jpg',
        desc: 'Kompetisi drone racing.',
      },
      {
        id: 'wf',
        title: 'WF',
        img: '/workshop-drone.jpg',
        desc: 'Workshop Festival.',
      },
      {
        id: 'triathlon',
        title: 'Triathlon Robot',
        img: '/workshop-drone.jpg',
        desc: 'Robot multi challenge.',
      },
      {
        id: 'psk',
        title: 'Proyek Sistem Komputer',
        img: '/workshop-drone.jpg',
        desc: 'Perancangan sistem komputer.',
      },
    ],
  },
};

const years = ['2022', '2025', '2026'];

export default function CompetitionsPage() {
  const [activeYear, setActiveYear] = useState('2026');
  const data = competitionsData[activeYear];
  const isCurrentYear = activeYear === '2026';

  return (
    <section className="competitions-section">
      <div className="container">

        {/* YEAR TAB */}
        <div className="year-tabs">
          {years.map(year => (
            <button
              key={year}
              className={`year-tab ${activeYear === year ? 'active' : ''}`}
              onClick={() => setActiveYear(year)}
            >
              {year}
            </button>
          ))}
        </div>

        {/* PANITIA */}
        <div className="panitia-img-wrap">
          <img src={data.panitia} alt="panitia" />
        </div>

        {/* EVENTS */}
        <div className="events-grid">
          {data.events.map((event, i) => (
            <div key={event.id} className="event-card">

              {/* BACKGROUND IMAGE FIX */}
              <div
                className="event-card-bg"
                style={{ backgroundImage: `url(${event.img})` }}
              />

              <div className="event-card-content">
                <span className="event-number">
                  {String(i + 1).padStart(2, '0')}
                </span>

                <div>
                  <h3>{event.title}</h3>
                  <p>{event.desc}</p>
                </div>
              </div>

            </div>
          ))}
        </div>

        {/* BUTTON */}
        <div className="daftar-competition-box">
          <div>
            <h2>
              {isCurrentYear
                ? 'Daftarkan Tim Kamu!'
                : `ESC ${activeYear} Telah Selesai`}
            </h2>
            <p>
              {isCurrentYear
                ? 'Pendaftaran masih dibuka.'
                : 'Kompetisi telah selesai.'}
            </p>
          </div>

          <button disabled={!isCurrentYear}>
            {isCurrentYear ? 'Daftar Sekarang' : 'Ditutup'}
          </button>
        </div>

      </div>
    </section>
  );
}
